def solve(*args):
    if not args:
        return None

    # Assuming args is a list of contract details
    contracts = []
    for contract in args:
        if isinstance(contract, dict) and 'template' in contract and 'data' in contract:
            contracts.append(contract)
        else:
            return None

    # Implement core logic to create documents from templates
    documents = []
    for contract in contracts:
        template = contract['template']
        data = contract['data']
        document = template.format(**data)  # Assuming template is a string with placeholders
        documents.append(document)

    return documents
